package firstlect;

public class incredecre {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		int j = 10;
		System.out.println(j);
		j = j+1;
		System.out.println(j);
		
		j += 7;
		System.out.println(j);
		
		j *= 5;
		System.out.println(j);
		
		j++;
		System.out.println(j);
		
	     ++j;
		System.out.println(j);
		
		int k = 10;
		System.out.println(k);
		
		++k;
		System.out.println(k);
		
		k++;
		System.out.println(k);	}

}
